## The Decoded String Table

The obfuscator uses a base64-encoded string array with rotation. After resolving all the encoded references, here's the clean, deobfuscated code:

```javascript
var TAU = 6.283;       // 2π
var PHI = 1.618;       // Golden ratio
var INV_SQRT2 = 0.707; // 1/√2

var config = {
  deflection: 4000,      // Repulsion strength between nodes
  frictionCoeff: 0.004,  // Friction/damping on spring forces
  approximation: 0.92,   // Velocity damping factor
  dispersal: 0.0003,     // Gravity toward center
  streamMax: 40,         // Max number of particles
  streamDecay: 0.04,     // Particle friction
  theta: 0.06            // Camera/lens interpolation speed
};

// Graph NODES (called "edges" in the obfuscated code — misleading names)
var edges = [
  { id: 'hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha',   label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta',    label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma',   label: 'Gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Graph EDGES/links (called "nodes" in the obfuscated code — also misleading)
var nodes = [
  { a: 'hub',   b: 'alpha',   rest: 160, k: 0.006 },
  { a: 'hub',   b: 'beta',    rest: 160, k: 0.005 },
  { a: 'hub',   b: 'gamma',   rest: 170, k: 0.004 },
  { a: 'hub',   b: 'delta',   rest: 170, k: 0.004 },
  { a: 'hub',   b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

var lens = { x: 400, y: 300, zoom: 1 };   // Current camera
var focus = { x: 400, y: 300, zoom: 1 };   // Target camera
var stream = [];  // Particle array
var cycle = 0;

function edgeById(id) {
  for (var i = 0; i < edges.length; i++) {
    if (edges[i].id === id) return edges[i];
  }
  return null;
}

// Main physics simulation step
function converge() {
  // 1. Coulomb repulsion: all node pairs repel each other
  for (var i = 0; i < edges.length; i++) {
    for (var j = i + 1; j < edges.length; j++) {
      var dx = edges[i].x - edges[j].x;
      var dy = edges[i].y - edges[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var force = config.deflection / (dist * dist);
      var fx = (dx / dist) * force;
      var fy = (dy / dist) * force;
      edges[i].vx += fx;
      edges[i].vy += fy;
      edges[j].vx -= fx;
      edges[j].vy -= fy;
    }
  }

  // 2. Spring attraction along links (Hooke's law)
  for (var n = 0; n < nodes.length; n++) {
    var nodeA = edgeById(nodes[n].a);
    var nodeB = edgeById(nodes[n].b);
    if (!nodeA || !nodeB) continue;
    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = dist - nodes[n].rest;
    var force = (nodes[n].k || config.frictionCoeff) * displacement;
    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // 3. Gravity toward center (400, 300) + velocity damping + position update
  for (var i = 0; i < edges.length; i++) {
    edges[i].vx += (400 - edges[i].x) * config.dispersal;
    edges[i].vy += (300 - edges[i].y) * config.dispersal;
    edges[i].vx *= config.approximation;  // 0.92 damping
    edges[i].vy *= config.approximation;
    edges[i].x += edges[i].vx;
    edges[i].y += edges[i].vy;
  }
}

// Spawn a particle from a random node
function emitStream() {
  if (stream.length >= config.streamMax) return;
  var source = edges[Math.floor(Math.random() * edges.length)];
  var angle = Math.random() * TAU;
  var speed = 0.3 + Math.random() * INV_SQRT2;
  stream.push({
    x: source.x,
    y: source.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * PHI * INV_SQRT2
  });
}

// Update and cull particles
function decayStream() {
  for (var i = stream.length - 1; i >= 0; i--) {
    var p = stream[i];
    p.vx *= 1 - config.streamDecay * 0.125;
    p.vy *= 1 - config.streamDecay * 0.125;
    p.x += p.vx;
    p.y += p.vy;
    p.age++;
    if (p.age > p.maxAge) stream.splice(i, 1);
  }
}

// Smoothly interpolate camera toward focus target
function adjustLens() {
  lens.x += (focus.x - lens.x) * config.theta;
  lens.y += (focus.y - lens.y) * config.theta;
  lens.zoom += (focus.zoom - lens.zoom) * config.theta;
}

// Main loop tick
function pulse() {
  converge();
  decayStream();
  adjustLens();
  if (cycle % 3 === 0) emitStream();  // Emit particle every 3rd frame
  cycle++;
}

setInterval(pulse, 16);  // ~60 FPS
```

---

## What It Does

This is a **force-directed graph layout simulation** with a **particle system**, running at ~60 FPS. Specifically:

### 1. **Force-Directed Graph (the physics engine)**
- **6 graph nodes** (hub, alpha, beta, gamma, delta, epsilon) are connected by **8 spring links**
- Three forces act on nodes each tick:
  - **Coulomb repulsion** — all nodes push each other away (inverse-square law)
  - **Spring attraction** — connected nodes are pulled toward a rest length (Hooke's law)
  - **Centering gravity** — gentle pull toward (400, 300) to keep the graph on-screen
- Velocities are **damped by 0.92** each frame to prevent oscillation

### 2. **Particle Stream (visual effect)**
- Every 3 frames, a particle spawns from a random node, flying off in a random direction
- Particles slowly decelerate and die after 800–2000 frames
- Capped at 40 particles max

### 3. **Camera System**
- A `lens` smoothly interpolates toward a `focus` target using lerp (6% per frame)
- This would support smooth panning/zooming in a renderer

### 4. **No rendering code is present** — this is purely the simulation/data layer. It would need a canvas/SVG renderer to actually display anything.

The deliberately **swapped variable names** (`edges` holds nodes, `nodes` holds edges) appear to be intentional obfuscation beyond the mechanical string encoding.
